interface Product {
  id: number;
  name: string;
  price: number;
  originalPrice?: number;
  image: string;
  images?: string[];
  rating: number;
  reviewCount: number;
  time: string;
  tag?: string;
  category: string;
  description: string;
}

interface CartItem extends Product {
  quantity: number;
}

interface Review {
  name: string;
  rating: number;
  comment: string;
  date: string;
  avatar: string;
}

